using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver — resolves any type.
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T>.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 37), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing.
//    With the default resolver every type resolves, so Person succeeds:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
    Console.WriteLine($"TryGetTypeInfo<Person> → resolved ({info!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Person> → not available");

// Now demonstrate the "not available" path.
// A source-gen context that only knows about Person:
var restricted = new JsonSerializerOptions { TypeInfoResolver = DemoContext.Default };

if (restricted.TryGetTypeInfo<Person>(out _))
    Console.WriteLine("TryGetTypeInfo<Person> on restricted → resolved");
else
    Console.WriteLine("TryGetTypeInfo<Person> on restricted → not available");

if (restricted.TryGetTypeInfo<int>(out _))
    Console.WriteLine("TryGetTypeInfo<int>    on restricted → resolved");
else
    Console.WriteLine("TryGetTypeInfo<int>    on restricted → NOT available (expected)");

public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
public partial class DemoContext : JsonSerializerContext;

